    if pd.isna(x) or str(x) == "None":
        return None
    return str(x).lstrip('#').strip()

df_con['CompanySignedDate'] = pd.to_datetime(df_con['CompanySignedDate']).dt.date
start_date = pd.to_datetime('2023-04-01').date()
